# GraphQL Types
class ReviewType(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_id = graphene.String(required=True)
    username = graphene.String(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    is_verified_purchase = graphene.Boolean()
    helpful_count = graphene.Int()
    created_at = graphene.String()


class ReviewConnection(graphene.ObjectType):
    items = graphene.List(ReviewType)
    total_count = graphene.Int()
    average_rating = graphene.Float()


class CategoryType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    slug = graphene.String(required=True)
    product_count = graphene.Int()
    products = graphene.List(lambda: ProductType, limit=graphene.Int(), offset=graphene.Int())

    def resolve_product_count(self, info):
        return len([p for p in PRODUCTS if p["category_id"] == self.id and p["is_active"]])

    def resolve_products(self, info, limit=None, offset=0):
        products = [p for p in PRODUCTS if p["category_id"] == self.id and p["is_active"]]
        products = products[offset:]
        if limit is not None:
            products = products[:limit]
        return [ProductType(**p) for p in products]


class PriceRangeType(graphene.ObjectType):
    min_price = graphene.Float()
    max_price = graphene.Float()
    currency = graphene.String()


class ProductType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    currency = graphene.String()
    sku = graphene.String(required=True)
    stock_quantity = graphene.Int()
    category_id = graphene.ID()
    category = graphene.Field(CategoryType)
    image_url = graphene.String()
    is_active = graphene.Boolean()
    is_in_stock = graphene.Boolean()
    created_at = graphene.String()
    updated_at = graphene.String()
    reviews = graphene.Field(
        ReviewConnection,
        limit=graphene.Int(),
        offset=graphene.Int(),
        min_rating=graphene.Int(),
        verified_only=graphene.Boolean(),
        sort_by=graphene.String(),
    )

    def resolve_category(self, info):
        cat = next((c for c in CATEGORIES if c["id"] == self.category_id), None)
        if cat:
            return CategoryType(**cat)
        return None

    def resolve_is_in_stock(self, info):
        return (self.stock_quantity or 0) > 0

    def resolve_reviews(self, info, limit=None, offset=0, min_rating=None, verified_only=False, sort_by=None):
        reviews = [r for r in REVIEWS if r["product_id"] == self.id]

        if min_rating is not None:
            reviews = [r for r in reviews if r["rating"] >= min_rating]

        if verified_only:
            reviews = [r for r in reviews if r["is_verified_purchase"]]

        total_count = len(reviews)
        average_rating = sum(r["rating"] for r in reviews) / total_count if total_count > 0 else 0.0

        if sort_by == "rating_desc":
            reviews.sort(key=lambda r: r["rating"], reverse=True)
        elif sort_by == "rating_asc":
            reviews.sort(key=lambda r: r["rating"])
        elif sort_by == "newest":
            reviews.sort(key=lambda r: r["created_at"], reverse=True)
        elif sort_by == "most_helpful":
            reviews.sort(key=lambda r: r["helpful_count"], reverse=True)
        else:
            reviews.sort(key=lambda r: r["created_at"], reverse=True)

        reviews = reviews[offset:]
        if limit is not None:
            reviews = reviews[:limit]

        return ReviewConnection(
            items=[ReviewType(**r) for r in reviews],
            total_count=total_count,
            average_rating=round(average_rating, 2),
        )


class ProductConnection(graphene.ObjectType):
    items = graphene.List(ProductType)
    total_count = graphene.Int()
    page_info = graphene.Field(lambda: PageInfoType)


class PageInfoType(graphene.ObjectType):
    has_next_page = graphene.Boolean()
    has_previous_page = graphene.Boolean()
    total_pages = graphene.Int()
    current_page = graphene.Int()


class ProductSortEnum(graphene.Enum):
    PRICE_ASC = "price_asc"
    PRICE_DESC = "price_desc"
    NAME_ASC = "name_asc"
    NAME_DESC = "name_desc"
    NEWEST = "newest"
    OLDEST = "oldest"


# Queries
class Query(graphene.ObjectType):
    # Product queries
    product = graphene.Field(
        ProductType,
        id=graphene.ID(),
        sku=graphene.String(),
        description="Fetch a single product by ID or SKU",
    )
    products = graphene.Field(
        ProductConnection,
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        category_id=graphene.ID(),
        search=graphene.String(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        in_stock_only=graphene.Boolean(default_value=False),
        is_active=graphene.Boolean(default_value=True),
        sort_by=ProductSortEnum(),
        description="Fetch a paginated list of products with filtering and sorting",
    )
    product_price_range = graphene.Field(
        PriceRangeType,
        category_id=graphene.ID(),
        description="Get the min and max price for products, optionally filtered by category",
    )

    # Category queries
    category = graphene.Field(
        CategoryType,
        id=graphene.ID(),
        slug=graphene.String(),
        description="Fetch a single category by ID or slug",
    )
    categories = graphene.List(
        CategoryType,
        description="Fetch all categories",
    )

    # Review queries
    review = graphene.Field(
        ReviewType,
        id=graphene.ID(required=True),
        description="Fetch a single review by ID",
    )
    reviews = graphene.Field(
        ReviewConnection,
        product_id=graphene.ID(),
        user_id=graphene.String(),
        min_rating=graphene.Int(),
        verified_only=graphene.Boolean(default_value=False),
        limit=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        sort_by=graphene.String(),
        description="Fetch reviews with filtering options",
    )

    # Search
    search_products = graphene.List(
        ProductType,
        query=graphene.String(required=True),
        limit=graphene.Int(default_value=10),
        description="Full-text search across product names and descriptions",
    )

    def resolve_product(self, info, id=None, sku=None):
        if id:
            product = next((p for p in PRODUCTS if p["id"] == id), None)
        elif sku:
            product = next((p for p in PRODUCTS if p["sku"] == sku), None)
        else:
            return None
        if product:
            return ProductType(**product)
        return None

    def resolve_products(self, info, limit=10, offset=0, category_id=None, search=None,
                         min_price=None, max_price=None, in_stock_only=False,
                         is_active=True, sort_by=None):
        filtered = list(PRODUCTS)

        if is_active is not None:
            filtered = [p for p in filtered if p["is_active"] == is_active]

        if category_id:
            filtered = [p for p in filtered if p["category_id"] == category_id]

        if search:
            search_lower = search.lower()
            filtered = [
                p for p in filtered
                if search_lower in p["name"].lower() or search_lower in p["description"].lower()
            ]

        if min_price is not None:
            filtered = [p for p in filtered if p["price"] >= min_price]

        if max_price is not None:
            filtered = [p for p in filtered if p["price"] <= max_price]

        if in_stock_only:
            filtered = [p for p in filtered if p["stock_quantity"] > 0]

        # Sorting
        if sort_by:
            sort_val = sort_by if isinstance(sort_by, str) else sort_by.value
            if sort_val == "price_asc":
                filtered.sort(key=lambda p: p["price"])
            elif sort_val == "price_desc":
                filtered.sort(key=lambda p: p["price"], reverse=True)
            elif sort_val == "name_asc":
                filtered.sort(key=lambda p: p["name"].lower())
            elif sort_val == "name_desc":
                filtered.sort(key=lambda p: p["name"].lower(), reverse=True)
            elif sort_val == "newest":
                filtered.sort(key=lambda p: p["created_at"], reverse=True)
            elif sort_val == "oldest":
                filtered.sort(key=lambda p: p["created_at"])

        total_count = len(filtered)
        total_pages = max(1, (total_count + limit - 1) // limit) if limit > 0 else 1
        current_page = (offset // limit) + 1 if limit > 0 else 1

        paginated = filtered[offset:offset + limit]

        return ProductConnection(
            items=[ProductType(**p) for p in paginated],
            total_count=total_count,
            page_info=PageInfoType(
                has_next_page=(offset + limit) < total_count,
                has_previous_page=offset > 0,
                total_pages=total_pages,
                current_page=current_page,
            ),
        )

    def resolve_product_price_range(self, info, category_id=None):
        filtered = [p for p in PRODUCTS if p["is_active"]]
        if category_id:
            filtered = [p for p in filtered if p["category_id"] == category_id]

        if not filtered:
            return PriceRangeType(min_price=0, max_price=0, currency="USD")

        prices = [p["price"] for p in filtered]
        return PriceRangeType(
            min_price=min(prices),
            max_price=max(prices),
            currency="USD",
        )

    def resolve_category(self, info, id=None, slug=None):
        if id:
            cat = next((c for c in CATEGORIES if c["id"] == id), None)
        elif slug:
            cat = next((c for c in CATEGORIES if c["slug"] == slug), None)
        else:
            return None
        if cat:
            return CategoryType(**cat)
        return None

    def resolve_categories(self, info):
        return [CategoryType(**c) for c in CATEGORIES]

    def resolve_review(self, info, id):
        review = next((r for r in REVIEWS if r["id"] == id), None)
        if review:
            return ReviewType(**review)
        return None

    def resolve_reviews(self, info, product_id=None, user_id=None, min_rating=None,
                        verified_only=False, limit=10, offset=0, sort_by=None):
        filtered = list(REVIEWS)

        if product_id:
            filtered = [r for r in filtered if r["product_id"] == product_id]

        if user_id:
            filtered = [r for r in filtered if r["user_id"] == user_id]

        if min_rating is not None:
            filtered = [r for r in filtered if r["rating"] >= min_rating]

        if verified_only:
            filtered = [r for r in filtered if r["is_verified_purchase"]]

        total_count = len(filtered)
        average_rating = sum(r["rating"] for r in filtered) / total_count if total_count > 0 else 0.0

        if sort_by == "rating_desc":
            filtered.sort(key=lambda r: r["rating"], reverse=True)
        elif sort_by == "rating_asc":
            filtered.sort(key=lambda r: r["rating"])
        elif sort_by == "newest":
            filtered.sort(key=lambda r: r["created_at"], reverse=True)
        elif sort_by == "most_helpful":
            filtered.sort(key=lambda r: r["helpful_count"], reverse=True)
        else:
            filtered.sort(key=lambda r: r["created_at"], reverse=True)

        paginated = filtered[offset:offset + limit]

        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total_count,
            average_rating=round(average_rating, 2),
        )

    def resolve_search_products(self, info, query, limit=10):
        query_lower = query.lower()
        results = []
        for p in PRODUCTS:
            if not p["is_active"]:
                continue
            score = 0
            if query_lower in p["name"].lower():
                score += 2
            if query_lower in p["description"].lower():
                score += 1
            if score > 0:
                results.append((score, p))

        results.sort(key=lambda x: x[0], reverse=True)
        return [ProductType(**p) for _, p in results[:limit]]


# Mutations
class AddReviewInput(graphene.InputObjectType):
    product_id = graphene.ID(required=True)
    user_id = graphene.String(required=True)
    username = graphene.String(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String(required=True)
    comment = graphene.String()
    is_verified_purchase = graphene.Boolean(default_value=False)


class AddReview(graphene.Mutation):
    class Arguments:
        input = AddReviewInput(required=True)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, input):
        # Validate rating
        if input.rating < 1 or input.rating > 5:
            return AddReview(review=None, success=False, message="Rating must be between 1 and 5")

        # Check product exists
        product = next((p for p in PRODUCTS if p["id"] == input.product_id), None)
        if not product:
            return AddReview(review=None, success=False, message="Product not found")

        new_id = str(max(int(r["id"]) for r in REVIEWS) + 1)
        new_review = {
            "id": new_id,
            "product_id": input.product_id,
            "user_id": input.user_id,
            "username": input.username,
            "rating": input.rating,
            "title": input.title,
            "comment": input.comment or "",
            "is_verified_purchase": input.is_verified_purchase,
            "helpful_count": 0,
            "created_at": datetime.utcnow().isoformat(),
        }
        REVIEWS.append(new_review)
        return AddReview(
            review=ReviewType(**new_review),
            success=True,
            message="Review added successfully",
        )


class MarkReviewHelpful(graphene.Mutation):
    class Arguments:
        review_id = graphene.ID(required=True)

    review = graphene.Field(ReviewType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, review_id):
        review = next((r for r in REVIEWS if r["id"] == review_id), None)
        if not review:
            return MarkReviewHelpful(review=None, success=False, message="Review not found")

        review["helpful_count"] = review.get("helpful_count", 0) + 1
        return MarkReviewHelpful(
            review=ReviewType(**review),
            success=True,
            message="Review marked as helpful",
        )


class UpdateProductStock(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        quantity = graphene.Int(required=True)

    product = graphene.Field(ProductType)
    success = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, product_id, quantity):
        product = next((p for p in PRODUCTS if p["id"] == product_id), None)
        if not product:
            return UpdateProductStock(product=None, success=False, message="Product not found")

        if quantity < 0:
            return UpdateProductStock(product=None, success=False, message="Quantity cannot be negative")

        product["stock_quantity"] = quantity
        product["updated_at"] = datetime.utcnow().isoformat()
        return UpdateProductStock(
            product=ProductType(**product),
            success=True,
            message=f"Stock updated to {quantity}",
        )


class Mutation(graphene.ObjectType):
    add_review = AddReview.Field(description="Add a new review for a product")
    mark_review_helpful = MarkReviewHelpful.Field(description="Mark a review as helpful")
    update_product_stock = UpdateProductStock.Field(description="Update product stock quantity")


# Schema - introspection enabled for development/testing
# TODO: Disable introspection in production by setting introspection=False
schema = graphene.Schema(query=Query, mutation=Mutation)

# Flask app
app = Flask(__name__)

app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,  # Enable GraphiQL interface for testing
    ),
)


@app.route("/")
def index():
    return {
        "service": "E-Commerce Product Catalog GraphQL API",
        "version": "1.0.0",
        "graphql_endpoint": "/graphql",
        "graphiql": "/graphql",
        "status": "running",
        "environment": "development",
        "note": "Introspection is enabled for development. Disable in production.",
    }


@app.route("/health")
def health():
    return {
        "status": "healthy",
        "products_count": len(PRODUCTS),
        "categories_count": len(CATEGORIES),
        "reviews_count": len(REVIEWS),
    }


